class Leaderboard:
    def __init__(self):
        self.mp = {}
    def addScore(self, playerId, score):
        self.mp[playerId] = self.mp.get(playerId, 0) + score
    def top(self, k):
        return sum(sorted(self.mp.values(), reverse=True)[:k])
    def reset(self, playerId):
        self.mp[playerId] = 0

